// On-device OCR check for scanned PDFs.
//
// ML Kit needs a real engine, so this runs as an integration test on an
// emulator/device, not under `flutter test`:
//
//   flutter test integration_test/ocr_test.dart -d <emulator>
//
// The scanned (image-only) fixture is embedded below as base64 so the test is
// self-contained and survives app reinstalls. It is NOT bundled into the app.
import 'dart:convert';
import 'dart:io';

import 'package:flutter_test/flutter_test.dart';
import 'package:integration_test/integration_test.dart';
import 'package:path_provider/path_provider.dart';
import 'package:papyr/services/pdf_text_extractor.dart';

void main() {
  IntegrationTestWidgetsFlutterBinding.ensureInitialized();

  test('OCR recovers structured text from a scanned PDF', () async {
    final dir = await getTemporaryDirectory();
    final path = '${dir.path}/scanned_sample.pdf';
    await File(path).writeAsBytes(base64.decode(_scannedPdfB64));

    // Text-only must find nothing (proves it really is image-only).
    final textOnly = await PdfTextExtractor.extractBlocks(path);
    expect(textOnly, isEmpty);

    // With OCR enabled, the words come back.
    final blocks = await PdfTextExtractor.extractBlocks(path, useOcr: true);
    expect(blocks, isNotEmpty);

    final all = blocks.map((b) => b.text.toLowerCase()).join(' ');
    expect(all, contains('reading should feel calm'));
    expect(all, contains('on-device ocr'));

    // The big title line should be detected as a heading, not body text.
    final headings =
        blocks.where((b) => b.isHeading).map((b) => b.text.toLowerCase());
    expect(headings.any((h) => h.contains('scanned chapter')), isTrue,
        reason: 'heading detection should flag the large title line');
  }, timeout: const Timeout(Duration(minutes: 3)));
}

